// Parse RSS and filter kid-friendly trends
const xml = $input.first().json.data;
const trends = [];

// Simple XML parsing for trend titles
const matches = xml.match(/<title>([^<]+)<\/title>/g) || [];
for (const match of matches.slice(1, 10)) {
  const title = match.replace(/<\/?title>/g, '');
  // Filter out adult/news topics
  const skipWords = ['death', 'killed', 'murder', 'war', 'attack', 'scandal', 'arrest'];
  if (!skipWords.some(word => title.toLowerCase().includes(word))) {
    trends.push(title);
  }
}

const selectedTrend = trends[Math.floor(Math.random() * Math.min(trends.length, 5))] || 'magical adventure';

return [{ json: { trend: selectedTrend } }];

