// Parse the story from Groq response
const response = $input.first().json;
let storyText = response.choices[0].message.content;

// Clean up and parse JSON
storyText = storyText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

try {
  const story = JSON.parse(storyText);
  return [{ json: story }];
} catch (e) {
  // Fallback story if parsing fails
  return [{ json: {
    title: "The Magical Garden",
    scenes: [
      { narration: "Once upon a time, there was a beautiful garden where flowers could talk and sing.", image_prompt: "cartoon magical garden with colorful talking flowers, bright sunshine, kid-friendly" },
      { narration: "A little butterfly named Bella loved to visit the garden every day.", image_prompt: "cute cartoon butterfly with big eyes in a flower garden, bright colors, children's illustration" },
      { narration: "One day, Bella found a flower that was sad because it hadn't bloomed yet.", image_prompt: "cartoon butterfly comforting a sad flower bud, gentle scene, pastel colors" },
      { narration: "Bella sang a happy song, and the flower began to bloom beautifully!", image_prompt: "cartoon butterfly singing with musical notes, flower blooming with sparkles, joyful scene" },
      { narration: "The moral of the story is: A kind word can help anyone bloom! The End.", image_prompt: "happy cartoon butterfly and blooming flower together, rainbow in background, 'The End' text" }
    ]
  }}];
}

// Generate images for each scene using Pollinations.ai (free)
const story = $input.first().json;
const scenes = story.scenes;
const imageUrls = [];

for (let i = 0; i < scenes.length; i++) {
  const prompt = encodeURIComponent(scenes[i].image_prompt + ', digital art, vibrant colors, safe for children');
  const imageUrl = `https://image.pollinations.ai/prompt/${prompt}?width=1280&height=720&seed=${Date.now() + i}`;
  imageUrls.push({
    sceneIndex: i,
    narration: scenes[i].narration,
    imageUrl: imageUrl
  });
}

return [{ json: { title: story.title, scenes: imageUrls } }];
